return items
  .map(item => {
    const title = item.json.title || '';
    const link = item.json.link || item.json.guid || '';
    const summary = item.json.contentSnippet || item.json.content || '';
    const text = `${title} ${summary}`.toLowerCase();
    const matched = keywords.filter(k => text.includes(k.toLowerCase()));
    return { json: { title, link, summary, matched_keywords: matched, relevance_score: matched.length } };
  })
  .filter(item => item.json.relevance_score > 0);

